import{_ as a,o as s,c as e,Q as n}from"./chunks/framework.6a72df8e.js";const l="/assets/image-1.b4d834da.png",i="/assets/image-3.7283bff4.png",r="/assets/image-2.fee6c3a9.png",t="/assets/image-5.3dfecd2f.png",p="/assets/image-6.5c663f7e.png",c="/assets/image-7.32b7d60b.png",d="/assets/image-8.62f9cb2b.png",o="/assets/image-9.f040bbd5.png",h="/assets/image-10.618e67d5.png",b="/assets/image-11.df973a4b.png",g="/assets/image-12.7ae480fc.png",m="/assets/image-13.0b74123f.png",_="/assets/image-14.2f452fe2.png",u="/assets/image-15.63575a2b.png",f="/assets/image-16.81a6a5a9.png",v="/assets/image-17.b71ac724.png",x="/assets/image-18.9d8e85f0.png",k="/assets/image-19.d6584b6f.png",y="/assets/image-21.5d93b782.png",C="/assets/image-20.45c03eca.png",X=JSON.parse('{"title":"02.数据表示","description":"","frontmatter":{"title":"02.数据表示","date":"2023-07-12T23:06:41.000Z","tags":[408,"计组"]},"headers":[{"level":2,"title":"BCD","slug":"bcd","link":"#bcd","children":[{"level":3,"title":"8421","slug":"_8421","link":"#_8421","children":[]},{"level":3,"title":"余三码","slug":"余三码","link":"#余三码","children":[]},{"level":3,"title":"2421 码","slug":"_2421-码","link":"#_2421-码","children":[]}]},{"level":2,"title":"数据范围","slug":"数据范围","link":"#数据范围","children":[]},{"level":2,"title":"定点小数","slug":"定点小数","link":"#定点小数","children":[]},{"level":2,"title":"奇偶校验码","slug":"奇偶校验码","link":"#奇偶校验码","children":[]},{"level":2,"title":"算术逻辑单元(ALU)","slug":"算术逻辑单元-alu","link":"#算术逻辑单元-alu","children":[{"level":3,"title":"一位全加器","slug":"一位全加器","link":"#一位全加器","children":[]},{"level":3,"title":"并行加法器","slug":"并行加法器","link":"#并行加法器","children":[]},{"level":3,"title":"补码加/减法器","slug":"补码加-减法器","link":"#补码加-减法器","children":[]},{"level":3,"title":"标志位生成","slug":"标志位生成","link":"#标志位生成","children":[]}]},{"level":2,"title":"移位运算","slug":"移位运算","link":"#移位运算","children":[{"level":3,"title":"算术移位","slug":"算术移位","link":"#算术移位","children":[]},{"level":3,"title":"逻辑移位","slug":"逻辑移位","link":"#逻辑移位","children":[]},{"level":3,"title":"循环移位","slug":"循环移位","link":"#循环移位","children":[]}]},{"level":2,"title":"定点数乘法运算","slug":"定点数乘法运算","link":"#定点数乘法运算","children":[{"level":3,"title":"原码一位乘法","slug":"原码一位乘法","link":"#原码一位乘法","children":[]},{"level":3,"title":"补码一位乘法","slug":"补码一位乘法","link":"#补码一位乘法","children":[]}]}],"relativePath":"src/408/计组/02.数据表示.md","lastUpdated":1700455155000}'),w={name:"src/408/计组/02.数据表示.md"},A=n(`<h1 id="_02-数据表示" tabindex="-1">02.数据表示 <a class="header-anchor" href="#_02-数据表示" aria-hidden="true">#</a></h1><h2 id="bcd" tabindex="-1">BCD <a class="header-anchor" href="#bcd" aria-hidden="true">#</a></h2><h3 id="_8421" tabindex="-1">8421 <a class="header-anchor" href="#_8421" aria-hidden="true">#</a></h3><p>8421 只表示一位十进制数所以表示范围是 0~9, 如果&gt;=10 则要+6</p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">    7  +  8</span></span>
<span class="line"><span style="color:#babed8;">= 0111 + 1000</span></span>
<span class="line"><span style="color:#babed8;">= 1111</span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>但是 15 用 8421 表示是 <code>0001 0101</code>, 这时候通过对<code>1111</code>+6: <img src="`+l+'" alt="1111 + 0110"> 得到<code>0001 0101</code>, 恰好是 15</p><h3 id="余三码" tabindex="-1">余三码 <a class="header-anchor" href="#余三码" aria-hidden="true">#</a></h3><p>那为了解决上述 +6 的问题, 出现了余三码, 对 0-9 范围内的数以 8421 码表示之后全都+3,这样后期进行加减运算之后就不需要考虑数字是否落在 0-9 范围内, 然后为大于 9 的数单独+6 了.</p><p>余三码不具有有权性, 属于无权码, 而 8421 属于有权码.</p><h3 id="_2421-码" tabindex="-1">2421 码 <a class="header-anchor" href="#_2421-码" aria-hidden="true">#</a></h3><p>每一个 2421 码只要与自身按位取反，便可得到该数按 9 的补数的 2421 码，比如 4 的 2421 码 0100 自身取反后就变为了 1011，即 5 的 2421 码。2421 码可以给运算带来方便，因为可以利用·其对 9 的补数将减法运算转变为加法运算</p><h2 id="数据范围" tabindex="-1">数据范围 <a class="header-anchor" href="#数据范围" aria-hidden="true">#</a></h2><p><img src="'+i+'" alt="数据范围"></p><p>移码就是对补码的符号位取反, 只能表示整数. 所以移码数据范围和补码一样</p><p><img src="'+r+'" alt="移码"> 移码刚好是 0x00~0xff, 适合在电路中对比大小, 常用于表示浮点数的阶码.</p><h2 id="定点小数" tabindex="-1">定点小数<sup class="footnote-ref"><a href="#fn1" id="fnref1">[1]</a></sup> <a class="header-anchor" href="#定点小数" aria-hidden="true">#</a></h2><p><img src="'+t+'" alt=""><img src="'+p+'" alt=""></p><p><strong>定点小数的转码规则:</strong><img src="'+c+'" alt=""></p><p>加减规则也一样, 先转成补码然后 运算.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>符号位也参与运算</p></div><p><strong>数据范围:</strong><img src="'+d+'" alt="范围"></p><p>定点小数拓展位数的时候 0 是追加在末尾, 定点整数拓展时 0 插入在符号位与数值位中间.</p><h2 id="奇偶校验码" tabindex="-1">奇偶校验码 <a class="header-anchor" href="#奇偶校验码" aria-hidden="true">#</a></h2><p><img src="'+o+'" alt=""></p><p>偶较验位的计算: 对有效信息位按位 xor</p><p>校验过程: 对奇偶校验码安位 xor, 是 1 则出错</p><h2 id="算术逻辑单元-alu" tabindex="-1">算术逻辑单元(ALU) <a class="header-anchor" href="#算术逻辑单元-alu" aria-hidden="true">#</a></h2><p>PS: <code>同或</code>是对 xor 进行取反</p><h3 id="一位全加器" tabindex="-1">一位全加器 <a class="header-anchor" href="#一位全加器" aria-hidden="true">#</a></h3><p><img src="'+h+'" alt=""></p><p><img src="'+b+'" alt="电路图"></p><h3 id="并行加法器" tabindex="-1">并行加法器 <a class="header-anchor" href="#并行加法器" aria-hidden="true">#</a></h3><p><strong>串行进位(行波进位)的并行加法器</strong>: 计算速度很大程度取决于进位计算的速度</p><p><img src="'+g+'" alt="串行的"></p><p><strong>并行进位加法器</strong>:</p><p><img src="'+m+'" alt="逻辑表达式"><img src="'+_+'" alt="电路"></p><p>因为逻辑越来越复杂, 一般只实现 4 位的并行加法器.</p><h3 id="补码加-减法器" tabindex="-1">补码加/减法器 <a class="header-anchor" href="#补码加-减法器" aria-hidden="true">#</a></h3><p><img src="'+u+'" alt=""></p><h3 id="标志位生成" tabindex="-1">标志位生成 <a class="header-anchor" href="#标志位生成" aria-hidden="true">#</a></h3><p><img src="'+f+'" alt=""></p><p>真简单, 不做讲解.</p><h2 id="移位运算" tabindex="-1">移位运算 <a class="header-anchor" href="#移位运算" aria-hidden="true">#</a></h2><h3 id="算术移位" tabindex="-1">算术移位 <a class="header-anchor" href="#算术移位" aria-hidden="true">#</a></h3><p>改变各个数码位和小数点的相对位置, 从而改变各个数码位的位权(相当于乘除2). 可用于实现乘除法.</p><ul><li>原码: 直接整体左右移动, 舍弃的如果==0, 则相当于除以2, 如果!=0, 则会丢失精度.</li><li>反码: 正数和原码相同, 负数: 右移高位补1, 左移低位补1.</li><li><strong>补码</strong>: 正数和原码相同, 负数复杂. <img src="'+v+'" alt=""> 因此左部分适用于反码算术移位的规则, 右部分使用原码的算术移位规则.</li></ul><h3 id="逻辑移位" tabindex="-1">逻辑移位 <a class="header-anchor" href="#逻辑移位" aria-hidden="true">#</a></h3><p><strong>对无符号数的算术移位.</strong></p><p><img src="'+x+'" alt=""></p><h3 id="循环移位" tabindex="-1">循环移位 <a class="header-anchor" href="#循环移位" aria-hidden="true">#</a></h3><p>带进位位的循环左移: CF放到最低位, 最高位放到CF</p><p>右移同理...</p><h2 id="定点数乘法运算" tabindex="-1">定点数乘法运算 <a class="header-anchor" href="#定点数乘法运算" aria-hidden="true">#</a></h2><h3 id="原码一位乘法" tabindex="-1">原码一位乘法 <a class="header-anchor" href="#原码一位乘法" aria-hidden="true">#</a></h3><p>数值位取绝对值进行乘法计算</p><p><img src="'+k+`" alt=""></p><div class="language- line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki material-theme-palenight" tabindex="0"><code><span class="line"><span style="color:#babed8;">ACC = 0</span></span>
<span class="line"><span style="color:#babed8;">MQ = abs(乘数)</span></span>
<span class="line"><span style="color:#babed8;">X = abs(被乘数)</span></span>
<span class="line"><span style="color:#babed8;">loop {</span></span>
<span class="line"><span style="color:#babed8;">    if MQ最低位 == 0:</span></span>
<span class="line"><span style="color:#babed8;">        ACC += X</span></span>
<span class="line"><span style="color:#babed8;">    else:</span></span>
<span class="line"><span style="color:#babed8;">        ACC += 0</span></span>
<span class="line"><span style="color:#babed8;">    MQ &gt;&gt;= 1</span></span>
<span class="line"><span style="color:#babed8;">    AC &gt;&gt;= 1, 被舍弃的最低位补到MQ的最高位</span></span>
<span class="line"><span style="color:#babed8;">}</span></span>
<span class="line"><span style="color:#babed8;"></span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h3 id="补码一位乘法" tabindex="-1">补码一位乘法 <a class="header-anchor" href="#补码一位乘法" aria-hidden="true">#</a></h3><p><img src="`+y+'" alt=""></p><p>由于MQ增加一位辅助位, ACC和X寄存器也各增加一位(做为双符号位), 乘数MQ使用单符号位, 被乘数X使用双符号位.</p><p><img src="'+C+'" alt=""></p><hr class="footnotes-sep"><section class="footnotes"><ol class="footnotes-list"><li id="fn1" class="footnote-item"><p>【王道计算机考研 计算机组成原理】 <a href="https://www.bilibili.com/video/BV1ps4y1d73V/?p=14&amp;share_source=copy_web&amp;vd_source=0a7e9572278635efd730c0077f8e7b45" target="_blank" rel="noreferrer">https://www.bilibili.com/video/BV1ps4y1d73V/?p=14&amp;share_source=copy_web&amp;vd_source=0a7e9572278635efd730c0077f8e7b45</a> <a href="#fnref1" class="footnote-backref">↩︎</a></p></li></ol></section>',63),Q=[A];function T(V,B,M,S,D,N){return s(),e("div",null,Q)}const $=a(w,[["render",T]]);export{X as __pageData,$ as default};
